        stats_classify("kc3", "Means from 500 random samples of 40 students each.", $distributionOptions, "c", "<p>Each value is a statistic from a sample, so it is a sampling distribution.</p>", "One dot is one mean.", "foundational", array("distribution type"))
    ),
    "guided_practice" => array(
        stats_written("g1", "short-response", "Put repeated-sampling steps in order.", "<p><strong>Model answer:</strong> Select a random sample of fixed size, calculate the chosen statistic, record it, repeat many times, and graph the recorded statistics.</p>", "Sample, calculate, record, repeat, graph.", "foundational", array("process")),
        stats_written("g2", "short-response", "What does one dot represent in a sampling distribution of means?", "<p><strong>Model answer:</strong> One dot is the mean calculated from all individual observations in one random sample of the fixed size.</p>", "Not one person.", "foundational", array("interpretation")),
        stats_written("g3", "short-response", "Explain unbiased estimator without saying every estimate is correct.", "<p><strong>Model answer:</strong> Across all possible random samples, the estimator's sampling distribution is centred at the true parameter, although individual estimates vary above and below it.</p>", "Long-run centre.", "proficient", array("bias")),
        stats_written("g4", "short-response", "How does larger n affect centre and spread for an unbiased estimator?", "<p><strong>Model answer:</strong> The centre remains at the same population parameter, while spread decreases and estimates become more precise.</p>", "Target unchanged, clustering tighter.", "proficient", array("sample size")),
        stats_written("g5", "error-analysis", "A student calls the 30 values in one sample a sampling distribution. Correct the statement.", "<p><strong>Model answer:</strong> Those 30 raw values form the sample distribution. A sampling distribution would contain a statistic from each of many samples of 30.</p>", "Raw values versus statistics.", "proficient", array("error analysis")),
        stats_written("g6", "short-response", "Can a precise estimator be biased? Explain.", "<p><strong>Model answer:</strong> Yes. A biased method may produce estimates tightly clustered around the wrong value. Precision describes spread, not accuracy of the centre.</p>", "Tight but off-centre.", "proficient", array("bias", "precision"))
    ),
    "independent_practice" => array(
