        stats_classify("i2", "Scores of every player in a league season.", $distributionOptions, "a", "<p>The complete population of player scores is shown.</p>", "Every relevant individual.", "foundational", array("distribution type")),
        stats_classify("i3", "Scores of 25 selected players.", $distributionOptions, "b", "<p>One sample's individual values form a sample distribution.</p>", "One selected group.", "foundational", array("distribution type")),
        stats_written("i4", "short-response", "Why do sample statistics vary?", "<p><strong>Model answer:</strong> Random samples contain different combinations of individuals, so their calculated summaries differ naturally even under the same method.</p>", "Different people, different summary.", "foundational", array("variability")),
        stats_written("i5", "short-response", "What three features describe a sampling distribution?", "<p><strong>Model answer:</strong> Centre, spread, and shape.</p>", "Same distribution language as before.", "foundational", array("description")),
        stats_written("i6", "short-response", "Why does a simulation use the same n on every repetition?", "<p><strong>Model answer:</strong> Sample size affects the statistic's variability and shape. Holding n fixed ensures the graph represents one defined sampling distribution rather than a mixture.</p>", "Control the sampling rule.", "proficient", array("simulation")),
        stats_written("i7", "error-analysis", "A student says 1,000 simulated samples remove bias from a convenience method. Explain.", "<p><strong>Model answer:</strong> Repetition reveals the convenience method's long-run distribution but does not change who can enter. Its centre may remain systematically wrong.</p>", "Simulation repeats the method exactly.", "advanced", array("bias")),
        stats_written("i8", "short-response", "Compare bias and variability using sampling-distribution features.", "<p><strong>Model answer:</strong> Bias is the distance between the sampling distribution's centre and target parameter. Variability is the spread of the distribution around its centre.</p>", "Centre versus spread.", "proficient", array("bias", "variability"))
    ),
    "summary" => array("Population and sample distributions contain individual values; sampling distributions contain statistics.", "Repeated samples of fixed size produce sampling variability.", "An unbiased estimator's sampling distribution is centred at its target parameter.", "Precision is lower spread, generally improved by larger random samples.", "Simulation approximates long-run behaviour of the specified sampling process."),
    "exit_ticket" => array(
